CREATE SCHEMA IF NOT EXISTS fixture_master_src;
SET search_path TO fixture_master_src;

CREATE TABLE master_assets ( asset_kennung text PRIMARY KEY, asset_name text, serien_nummer text, garantieende text, kunden_kennung text, projekt_kennung text );


CREATE TABLE master_kontakte ( kontakt_id text PRIMARY KEY, rufname text, familienname text, kontakt_email text, tel text, berufsbezeichnung text, rolle text, korrespondenzsprache text, kd_nummer text );


CREATE TABLE master_kunden ( kundennummer text PRIMARY KEY, unternehmensname text, erp_nr text, kundenklasse text, vertriebsgebiet text, industrie text, homepage text, stadt text, land_region text );


CREATE TABLE master_opportunities ( opp_kennung text PRIMARY KEY, titel text, vertriebsphase text, zieldatum text, auftragswert text, waehrungscode text, kunden_ref text );


CREATE TABLE master_projekte ( projekt_kennung text PRIMARY KEY, projektname text, projektstatus text, go_live_datum text, kunden_kennung text, opp_kennung_ref text );

